    gsGet("Expenses",function(rows){expenses=rows.slice(1).map(function(r){return {id:r[0],date:r[1],vendor:r[4],category:r[3],amount:+r[6]||0};}).sort(function(a,b){return b.date>a.date?1:-1;}).slice(0,5);check();});
    gsGet("Analytics",function(rows){analytics=rows.slice(1).map(function(r){return {reach:+r[5]||0,leads:+r[10]||0};});check();});
